                          fontSize: "0.5rem",
                          letterSpacing: "0.22em",
                          textTransform: "uppercase",
                          color: "var(--amber)",
                          border: "1px solid var(--amber-dim)",
                          padding: "0.08rem 0.38rem",
                          borderRadius: "2px",
                          flexShrink: 0,
